// 解説：Google Mapsなどを使ってPTの位置をピンで表示
import { GoogleMap, Marker, useJsApiLoader } from '@react-google-maps/api';

export default function Map({ therapists }) {
  const { isLoaded } = useJsApiLoader({ googleMapsApiKey: "YOUR_API_KEY" });

  return isLoaded ? (
    <GoogleMap zoom={10} center={{ lat: 35.68, lng: 139.76 }}>
      {therapists.map(tp => (
        <Marker key={tp.id} position={{ lat: tp.lat, lng: tp.lng }} />
      ))}
    </GoogleMap>
  ) : null;
}